1	export interface Item {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	}
7	
8	export interface QuoteStep {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	export interface Damage {
14	  itemType: string;
15	  amount: number;
16	}
17	
18	export interface ClaimStep {
19	  op: "claim";
20	  policy: number;
21	  incident: { cause: string; damages: Damage[] };
22	}
23	
24	export type Step = QuoteStep | ClaimStep;
25	
26	export interface Scenario {
27	  customer: Customer;
28	  steps: Step[];
29	}
30	
31	type Customer = { yearsWithMHPCO: number };
32	
33	export interface QuoteResult { premium: number }
34	export interface ClaimResult { payout: number; remainingCap: number }
35	
36	export interface ScenarioResult {
37	  results: (QuoteResult | ClaimResult)[];
38	}
39	
40	const PROCESSING_FEE = 5;
41	
42	const BASE_PRICE_BY_TYPE: Record<string, number> = {
43	  sword: 100,
44	  amulet: 60,
45	  staff: 80,
46	  potion: 40,
47	  rune: 25,
48	  moonstone: 25,
49	};
50	
51	const INSURANCE_VALUE_BY_TYPE: Record<string, number> = {
52	  sword: 1000,
53	  amulet: 600,
54	  staff: 800,
55	  potion: 400,
56	  rune: 250,
57	  moonstone: 250,
58	};
59	
60	const DEDUCTIBLE = 100;
61	const CAP_MULTIPLIER = 2;
62	
63	const basePriceFor = (item: Item): number => {
64	  if (!(item.type in BASE_PRICE_BY_TYPE)) {
65	    throw new Error(`Unknown item type: ${item.type}`);
66	  }
67	  return BASE_PRICE_BY_TYPE[item.type];
68	};
69	
70	const COMPONENT_BLOCK_SIZE = 3;
71	const COMPONENT_BLOCK_PRICE = 60;
72	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
73	
74	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
75	
76	const sumBasePrices = (items: Item[]): number =>
77	  items.reduce((s, i) => s + basePriceFor(i), 0);
78	
79	const groupByType = (items: Item[]): Map<string, Item[]> => {
80	  const map = new Map<string, Item[]>();
81	  for (const item of items) {
82	    const list = map.get(item.type) ?? [];
83	    list.push(item);
84	    map.set(item.type, list);
85	  }
86	  return map;
87	};
88	
89	const priceForComponentGroup = (group: Item[]): number =>
90	  group.length === COMPONENT_BLOCK_SIZE
91	    ? COMPONENT_BLOCK_PRICE
92	    : sumBasePrices(group);
93	
94	const componentsPremium = (components: Item[]): number =>
95	  Array.from(groupByType(components).values())
96	    .reduce((sum, group) => sum + priceForComponentGroup(group), 0);
97	
98	const itemsBasePremium = (items: Item[]): number => {
99	  const components = items.filter(isComponent);
100	  const nonComponents = items.filter((i) => !isComponent(i));
101	  return sumBasePrices(nonComponents) + componentsPremium(components);
102	};
103	
104	const CURSE_SURCHARGE_RATE = 0.5;
105	const HIGH_ENCHANTMENT_RATE = 0.3;
106	const HIGH_ENCHANTMENT_THRESHOLD = 5;
107	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
108	const LOYALTY_DISCOUNT_RATE = 0.2;
109	const LOYALTY_YEARS_THRESHOLD = 2;
110	const FOLLOW_UP_DISCOUNT_RATE = 0.15;
111	
112	const perItemSurchargeRate = (item: Item): number =>
113	  (item.cursed ? CURSE_SURCHARGE_RATE : 0) +
114	  ((item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD ? HIGH_ENCHANTMENT_RATE : 0);
115	
116	const itemSurcharges = (items: Item[]): number =>
117	  items.reduce((sum, item) => sum + basePriceFor(item) * perItemSurchargeRate(item), 0);
118	
119	const isLoyal = (customer: Customer): boolean =>
120	  customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD;
121	
122	const loyaltyDiscountFor = (base: number, customer: Customer): number =>
123	  isLoyal(customer) ? base * LOYALTY_DISCOUNT_RATE : 0;
124	
125	const followUpDiscountFor = (base: number, isFollowUp: boolean): number =>
126	  isFollowUp ? base * FOLLOW_UP_DISCOUNT_RATE : 0;
127	
128	const quotePremium = (step: QuoteStep, customer: Customer, isFollowUp: boolean): number => {
129	  const base = itemsBasePremium(step.items);
130	  const total = base
131	    + itemSurcharges(step.items)
132	    + base * FIRST_INSURANCE_SURCHARGE_RATE
133	    - loyaltyDiscountFor(base, customer)
